import axios from 'axios';
import { ref, computed, reactive } from 'vue';

// Singleton state — shared across all components that call useBacktestApi()
const api = axios.create({
  baseURL: (typeof window !== 'undefined' ? window.location.origin : '') + '/lumitrade/bt/api/v1',
  timeout: 30000,
  withCredentials: true,
});

api.interceptors.request.use((config) => {
  try {
    const stored = JSON.parse(localStorage.getItem('ftAuthLoginInfo') || '{}');
      const btBot = stored['ftbot.1'];
      if (btBot?.accessToken) {
        config.headers.Authorization = `Bearer ${btBot.accessToken}`;
      }
    } catch {}
    return config;
  });

// Singleton state — shared across all useBacktestApi() calls
const backtestHistory = reactive<Record<string, any>>({});
const backtestHistoryList = ref<any[]>([]);
const selectedBacktestResultKey = ref('');
const backtestRunning = ref(false);
const backtestProgress = ref(0);
const backtestStep = ref('');
const backtestTradeCount = ref(0);
const canRunBacktest = ref(false);
const botFeatures = reactive({
  backtestFreqAI: false,
  backtestHistory: false,
  backtestSetNotes: false,
  backtestDelete: false,
});

const selectedBacktestResult = computed(() => {
  const key = selectedBacktestResultKey.value;
  if (!key || !backtestHistory[key]) return undefined;
  return backtestHistory[key];
});

const hasBacktestResult = computed(() => Object.keys(backtestHistory).length > 0);

export function useBacktestApi() {
  // Methods
  async function getState() {
    try {
    const { data } = await api.get('/show_config');
    console.log('[useBacktestApi] getState:', data?.runmode, 'api:', data?.api_version);
    canRunBacktest.value = data.runmode === 'webserver';
    // Evaluate features based on API version
    const ver = parseFloat(data.api_version || '0');
    botFeatures.backtestFreqAI = ver >= 2.22;
    botFeatures.backtestHistory = ver >= 2.31;
    botFeatures.backtestSetNotes = ver >= 2.44;
    botFeatures.backtestDelete = ver >= 2.31;
    return data;
    } catch (e: any) {
      console.error('[useBacktestApi] getState failed:', e.response?.status, e.message);
      return {};
    }
  }

  async function startBacktest(payload: any) {
    const { data } = await api.post('/backtest', payload);
    backtestRunning.value = true;
    return data;
  }

  async function pollBacktest() {
    const { data } = await api.get('/backtest');
    if (data.running) {
      backtestRunning.value = true;
      backtestProgress.value = data.progress || 0;
      backtestStep.value = data.step || '';
      backtestTradeCount.value = data.trade_count || 0;
    } else {
      backtestRunning.value = false;
      if (data.backtest_result) {
        updateBacktestResult(data.backtest_result);
      }
    }
    return data;
  }

  function updateBacktestResult(result: Record<string, any>) {
    // Parse the nested result structure (same logic as ftbot.ts)
    for (const [strategyName, strategyResult] of Object.entries(result)) {
      if (strategyName === 'metadata') continue;
      const key = (strategyResult as any).key || `${strategyName}_${Date.now()}`;
      backtestHistory[key] = {
        strategy: { [strategyName]: strategyResult },
        metadata: (result.metadata as any)?.[strategyName] || {},
      };
      if (!selectedBacktestResultKey.value) {
        selectedBacktestResultKey.value = key;
      }
    }
  }

  async function stopBacktest() {
    await api.get('/backtest/abort');
    backtestRunning.value = false;
  }

  async function removeBacktest() {
    await api.delete('/backtest');
    // Clear state
    Object.keys(backtestHistory).forEach((k) => delete backtestHistory[k]);
    selectedBacktestResultKey.value = '';
    backtestRunning.value = false;
  }

  async function getBacktestHistory() {
    try {
      const { data } = await api.get('/backtest/history');
      backtestHistoryList.value = data || [];
      console.log('[useBacktestApi] loaded', backtestHistoryList.value.length, 'history entries');
      return data;
    } catch (e: any) {
      console.error('[useBacktestApi] getBacktestHistory failed:', e.response?.status, e.message);
      return [];
    }
  }

  async function getBacktestHistoryResult(entry: { filename: string; strategy: string }) {
    const { data } = await api.get('/backtest/history/result', {
      params: { filename: entry.filename, strategy: entry.strategy },
    });
    if (data) {
      updateBacktestResult(data);
    }
    return data;
  }

  async function deleteBacktestHistoryResult(entry: { filename: string }) {
    await api.delete(`/backtest/history/${entry.filename}`);
    backtestHistoryList.value = backtestHistoryList.value.filter(
      (e: any) => e.filename !== entry.filename,
    );
  }

  async function saveBacktestResultMetadata(payload: {
    filename: string;
    strategy: string;
    notes: string;
  }) {
    await api.patch(`/backtest/history/${payload.filename}`, {
      strategy: payload.strategy,
      notes: payload.notes,
    });
  }

  async function getStrategy(name: string) {
    const { data } = await api.get(`/strategy/${name}`);
    return data;
  }

  function setBacktestResultKey(key: string) {
    selectedBacktestResultKey.value = key;
  }

  function removeBacktestResultFromMemory(key: string) {
    delete backtestHistory[key];
    if (selectedBacktestResultKey.value === key) {
      const keys = Object.keys(backtestHistory);
      selectedBacktestResultKey.value = keys.length > 0 ? keys[0] : '';
    }
  }

  return {
    // State
    backtestHistory,
    backtestHistoryList,
    selectedBacktestResultKey,
    selectedBacktestResult,
    hasBacktestResult,
    backtestRunning,
    backtestProgress,
    backtestStep,
    backtestTradeCount,
    canRunBacktest,
    botFeatures,
    // Methods
    getState,
    startBacktest,
    pollBacktest,
    stopBacktest,
    removeBacktest,
    getBacktestHistory,
    getBacktestHistoryResult,
    deleteBacktestHistoryResult,
    saveBacktestResultMetadata,
    getStrategy,
    setBacktestResultKey,
    removeBacktestResultFromMemory,
  };
}
